import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { API_BASE_URL } from '../config';

const EventerRegister = () => {
  const navigate = useNavigate();

  const [eventerData, setEventerData] = useState({
    eventer_name: '',
    // Add other fields as necessary
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setEventerData({ ...eventerData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch(`${API_BASE_URL}/eventer/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(eventerData),
      });
      if (!response.ok) throw new Error('Eventer registration failed');
      // Reset form or handle success
      setEventerData({ eventer_name: '' });
      navigate('/home'); // Adjust the navigate path as needed
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div>
        <h1>イベンター用のアカウント登録画面</h1>
        <form onSubmit={handleSubmit}>
        <label>
            Eventer Name:
            <input
            type="text"
            name="eventer_name"
            value={eventerData.eventer_name}
            onChange={handleInputChange}
            required
            />
        </label>
        {/* Add other input fields as necessary */}
        <button type="submit">Register Eventer</button>
        </form>
    </div>
  );
};

export default EventerRegister;
